1	#requires -Version 5
2	<#
3	  sync.ps1 — 從 canonical 正本投影 skills 到各 CLI(Windows junction)
4	
5	  來源(兩正本的 skills/<domain>/<name>):
6	    個人 general : $PersonalRoot\skills\general\*
7	    公司 slot    : $CorpRoot\skills\slot\*
8	  目標 CLI:
9	    ~/.kiro/skills, ~/.claude/skills
10	
11	  安全設計:
12	    - 預設 DRY-RUN(只印不動)。加 -Apply 才實際執行。
13	    - 移除既有 junction 用 `rmdir`(只刪連結,不碰正本內容);真實資料夾才用 Remove-Item。
14	    - 冪等:重跑只會重建連結。
15	#>
16	param([switch]$Apply)
17	
18	$ErrorActionPreference = 'Stop'
19	$PersonalRoot = 'G:\AI\AI-canonical'
20	$CorpRoot     = 'G:\AI\AI-canonical-corp'
21	$Targets = @(
22	  'C:\Users\jiunchiwang\.kiro\skills',
23	  'C:\Users\jiunchiwang\.claude\skills'
24	)
25	$DryRun = -not $Apply
26	
27	function Test-Reparse($path){
28	  $it = Get-Item $path -Force -ErrorAction SilentlyContinue
29	  return ($it -and ($it.Attributes -band [IO.FileAttributes]::ReparsePoint))
30	}
31	function Remove-Target($path){
32	  if(-not (Test-Path $path)){ return }
33	  if(Test-Reparse $path){ cmd /c rmdir "$path" | Out-Null }   # junction:只刪連結
34	  else { Remove-Item $path -Recurse -Force }                   # 真實資料夾
35	}
36	
37	# 掃兩個正本,建 skill 名 -> 正本路徑 對照
38	$sources = @{}
39	foreach($root in @("$PersonalRoot\skills","$CorpRoot\skills")){
40	  if(-not (Test-Path $root)){ continue }
41	  Get-ChildItem $root -Directory | ForEach-Object {           # domain
42	    Get-ChildItem $_.FullName -Directory | ForEach-Object {   # skill
43	      if($sources.ContainsKey($_.Name)){ Write-Host ("[warn] 重複 skill 名: " + $_.Name) -ForegroundColor Yellow }
44	      $sources[$_.Name] = $_.FullName
45	    }
46	  }
47	}
48	
49	Write-Host ("[mode]    " + $(if($DryRun){'DRY-RUN(只印不動;加 -Apply 才執行)'}else{'APPLY'}))
50	Write-Host ("[sources] 找到 " + $sources.Count + " 個 skill 正本")
51	
52	foreach($t in $Targets){
53	  if(-not (Test-Path $t)){
54	    if($DryRun){ Write-Host "  [would-mkdir] $t" } else { New-Item -ItemType Directory -Force -Path $t | Out-Null }
55	  }
56	  Write-Host "`n=== target: $t ==="
57	  foreach($name in ($sources.Keys | Sort-Object)){
58	    $src = $sources[$name]
59	    $dst = Join-Path $t $name
60	    $exists = Test-Path $dst
61	    $isLink = $exists -and (Test-Reparse $dst)
62	    if($DryRun){
63	      if($isLink){ Write-Host "  [relink]  $name" }
64	      elseif($exists){ Write-Host "  [replace] $name  (現為真實資料夾 -> 改 junction)" }
65	      else { Write-Host "  [link]    $name" }
66	      continue
67	    }
68	    Remove-Target $dst
69	    cmd /c mklink /J "$dst" "$src" | Out-Null
70	    Write-Host "  [ok] $name -> $src"
71	  }
72	}
73	# ─── steering(copy 投影 —— 正本為來源,edit 請改正本再 sync)───
74	#   Kiro       :開機自動載入 ~/.kiro/steering/*.md
75	#   Claude Code:無 steering 概念 → copy 到 ~/.claude/steering/,再由 CLAUDE.md @import
76	$steerSrc  = Join-Path $PersonalRoot "steering"
77	$steerDsts = @(
78	  "C:\Users\jiunchiwang\.kiro\steering",
79	  "C:\Users\jiunchiwang\.claude\steering"
80	)
81	if(Test-Path $steerSrc){
82	  foreach($steerDst in $steerDsts){
83	    Write-Host "`n=== steering → $steerDst (copy) ==="
84	    if(-not (Test-Path $steerDst)){ if(-not $DryRun){ New-Item -ItemType Directory -Force -Path $steerDst | Out-Null } }
85	    foreach($f in (Get-ChildItem $steerSrc -File -Filter *.md)){
86	      if($DryRun){ Write-Host "  [would-copy] $($f.Name)" }
87	      else { Copy-Item $f.FullName (Join-Path $steerDst $f.Name) -Force; Write-Host "  [copied] $($f.Name)" }
88	    }
89	  }
90	  # Claude Code 沒有 steering 機制 → 冪等確保全域 CLAUDE.md @import skill-workflow
91	  $claudeMd   = "C:\Users\jiunchiwang\.claude\CLAUDE.md"
92	  $importLine = "@steering/skill-workflow.md"
93	  if(Test-Path $claudeMd){
94	    Write-Host "`n=== CLAUDE.md @import 守衛 ==="
95	    $content = [System.IO.File]::ReadAllText($claudeMd, [System.Text.Encoding]::UTF8)
96	    if($content -match [regex]::Escape($importLine)){
97	      Write-Host "  [ok] CLAUDE.md 已含 $importLine"
98	    } elseif($DryRun){
99	      Write-Host "  [would-append] $importLine -> CLAUDE.md"
100	    } else {
101	      $block = "`r`n# ===================================================`r`n# Personal AI OS — Canonical Skill Workflow(投影自 steering;勿編輯投影,改正本)`r`n# ===================================================`r`n$importLine`r`n"
102	      [System.IO.File]::AppendAllText($claudeMd, $block, (New-Object System.Text.UTF8Encoding $false))
103	      Write-Host "  [appended] $importLine -> CLAUDE.md"
104	    }
105	  }
106	}
107	
108	if($DryRun){ Write-Host "`n完成(DRY-RUN:沒有任何變更。確認後加 -Apply 執行)。" }
109	else { Write-Host "`n完成(已套用 junction + steering copy)。" }
110

