#!/usr/bin/env python3
"""唯讀 recon v2：加班單表單，只抓可見的實際填寫控制項 + 每列的標籤文字（濾掉 RadEditor 內部雜訊）。"""
import json, os, sys
sys.path.insert(0, r"G:\AI\AI-canonical-corp\skills\office\vc-uof-hours\scripts")
from playwright.sync_api import sync_playwright

CONFIG_PATH = os.path.expanduser("~/.config/uof/config.json")
BASE = "http://uof/UOF/"
OVERTIME_FORM = "WKF/FormUse/PersonalBox/ApplyFormList.aspx?fillFormDirectly=true&formId=cd8fb94e-a539-4c7e-9762-43e87e653ced"

with open(CONFIG_PATH, encoding="utf-8") as f:
    cfg = json.load(f)
acct, pw = cfg["account"], cfg["password"]

with sync_playwright() as p:
    browser = p.chromium.launch(headless=True)
    ctx = browser.new_context(locale="zh-TW", viewport={"width": 1600, "height": 1600})
    page = ctx.new_page()

    page.goto(BASE + "Login.aspx", wait_until="domcontentloaded", timeout=20000)
    page.fill("#txtAccount", acct)
    page.fill("#txtPwd", pw)
    page.click("#btnSubmit")
    for _ in range(30):
        page.wait_for_timeout(500)
        try:
            url = page.url
        except Exception:
            continue
        if "login.aspx" not in url.lower():
            break
        try:
            if page.query_selector("#btnRemoveRepeatLogin") and page.query_selector("#btnRemoveRepeatLogin").is_visible():
                page.click("#btnRemoveRepeatLogin")
                page.wait_for_timeout(2000)
        except Exception:
            pass

    page.goto(BASE + OVERTIME_FORM, wait_until="networkidle", timeout=40000)
    page.wait_for_timeout(5000)

    target_frame = None
    for fr in page.frames:
        try:
            if fr.query_selector("[id*='VersionFieldCollectionUsingUC1']"):
                target_frame = fr
        except Exception:
            pass

    if not target_frame:
        print("找不到表單 frame")
    else:
        data = target_frame.evaluate("""
        () => {
          // 只挑最外層 versionFieldUC<N> 容器（不含底下巢狀的 RadEditor 內部元件）
          const containers = Array.from(document.querySelectorAll('[id*="versionFieldUC"]'))
            .filter(el => /versionFieldUC\\d+(_(UpdatePanel1|PanelNormal))?$/.test(el.id));
          const seen = new Set();
          const out = [];
          containers.forEach(el => {
            const m = el.id.match(/versionFieldUC(\\d+)/);
            if (!m) return;
            const n = m[1];
            if (seen.has(n)) return;
            seen.add(n);
            const tr = el.closest('tr');
            let label = '';
            if (tr) {
              const tds = Array.from(tr.querySelectorAll('td'));
              if (tds.length > 0) label = (tds[0].innerText || '').replace(/\\s+/g,' ').trim();
            }
            // 只抓這個 tr 內「淺層」可見控制項(排除 RadEditor 內部大量 hidden/file 元件)
            const controls = tr ? Array.from(tr.querySelectorAll('input, select, textarea'))
              .filter(c => {
                const t = (c.type||'').toLowerCase();
                if (['hidden','image','button'].includes(t)) return false;
                if (c.id.includes('RadEditor') || c.id.includes('FileCenter')) return false;
                return c.offsetParent !== null;
              })
              .map(c => ({tag: c.tagName, id: c.id, name: c.name, type: c.type||'', value: c.value})) : [];
            out.push({n, container_id: el.id, label, controls});
          });
          return out;
        }
        """)
        print("=== 加班單欄位（過濾後）===")
        print(json.dumps(data, ensure_ascii=False, indent=1))

        target_frame.screenshot(path=r"C:\Users\jiunchiwang\AppData\Local\Temp\uof_overtime_form.png", full_page=True)
        print("截圖: uof_overtime_form.png")

    ctx.close()
    browser.close()

